// Guardrail: the Symposium config webview runs an INLINE script generated by
// renderConfigScript() (configScript.ts) which concatenates several template
// fragments (configViews, configScriptMcp, …). Because that source is TS that is
// INLINED as raw JS into the webview, any TS-only syntax left inside the
// templates (e.g. `as HtmlInputElement`, `(m: {…})`) becomes a SyntaxError in the
// browser and the whole config panel fails to load. node --check on the emitted
// string catches that before install.
import { renderConfigScript } from "../out/ui/configScript.js";
import { makeConfigDict } from "../out/ui/configI18n.js";
import { execSync } from "node:child_process";
import { writeFileSync, unlinkSync } from "node:fs";

const tmp = `${process.cwd()}/out/_config-script-check.js`;
try {
    const script = renderConfigScript(makeConfigDict("pt-br"));
    writeFileSync(tmp, script);
    execSync(`node --check ${tmp}`, { stdio: "inherit" });
    console.log("✓ config webview inline script is valid JS");
} finally {
    try { unlinkSync(tmp); } catch { /* already gone */ }
}
